public record CheckSum {
    
    public record Md5 (
        byte[] V1
    ) : CheckSum {}
    
    public record Sha1 (
        byte[] V1
    ) : CheckSum {}
    
    public record Fnv1a32 (
        byte[] V1
    ) : CheckSum {}
    
    public record Fnv1a32x4 (
        byte[] V1
    ) : CheckSum {}
    

    
}

class FfiConverterTypeCheckSum : FfiConverterRustBuffer<CheckSum>{
    public static FfiConverterRustBuffer<CheckSum> INSTANCE = new FfiConverterTypeCheckSum();

    public override CheckSum Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new CheckSum.Md5(
                    FfiConverterByteArray.INSTANCE.Read(stream)
                );
            case 2:
                return new CheckSum.Sha1(
                    FfiConverterByteArray.INSTANCE.Read(stream)
                );
            case 3:
                return new CheckSum.Fnv1a32(
                    FfiConverterByteArray.INSTANCE.Read(stream)
                );
            case 4:
                return new CheckSum.Fnv1a32x4(
                    FfiConverterByteArray.INSTANCE.Read(stream)
                );
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeCheckSum.Read()", value));
        }
    }

    public override int AllocationSize(CheckSum value) {
        switch (value) {
            case CheckSum.Md5 variant_value:
                return 4
                    + FfiConverterByteArray.INSTANCE.AllocationSize(variant_value.V1);
            case CheckSum.Sha1 variant_value:
                return 4
                    + FfiConverterByteArray.INSTANCE.AllocationSize(variant_value.V1);
            case CheckSum.Fnv1a32 variant_value:
                return 4
                    + FfiConverterByteArray.INSTANCE.AllocationSize(variant_value.V1);
            case CheckSum.Fnv1a32x4 variant_value:
                return 4
                    + FfiConverterByteArray.INSTANCE.AllocationSize(variant_value.V1);
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeCheckSum.AllocationSize()", value));
        }
    }

    public override void Write(CheckSum value, BigEndianStream stream) {
        switch (value) {
            case CheckSum.Md5 variant_value:
                stream.WriteInt(1);
                FfiConverterByteArray.INSTANCE.Write(variant_value.V1, stream);
                break;
            case CheckSum.Sha1 variant_value:
                stream.WriteInt(2);
                FfiConverterByteArray.INSTANCE.Write(variant_value.V1, stream);
                break;
            case CheckSum.Fnv1a32 variant_value:
                stream.WriteInt(3);
                FfiConverterByteArray.INSTANCE.Write(variant_value.V1, stream);
                break;
            case CheckSum.Fnv1a32x4 variant_value:
                stream.WriteInt(4);
                FfiConverterByteArray.INSTANCE.Write(variant_value.V1, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeCheckSum.Write()", value));
        }
    }
}







