public record Revision {
    
    public record Unspecified: Revision {}
    
    
    public record Number (
        uint V1
    ) : Revision {}
    
    public record Date (
        long V1
    ) : Revision {}
    
    public record Committed: Revision {}
    
    
    public record Previous: Revision {}
    
    
    public record Base: Revision {}
    
    
    public record Working: Revision {}
    
    
    public record Head: Revision {}
    
    

    
}

class FfiConverterTypeRevision : FfiConverterRustBuffer<Revision>{
    public static FfiConverterRustBuffer<Revision> INSTANCE = new FfiConverterTypeRevision();

    public override Revision Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new Revision.Unspecified(
                );
            case 2:
                return new Revision.Number(
                    FfiConverterUInt32.INSTANCE.Read(stream)
                );
            case 3:
                return new Revision.Date(
                    FfiConverterInt64.INSTANCE.Read(stream)
                );
            case 4:
                return new Revision.Committed(
                );
            case 5:
                return new Revision.Previous(
                );
            case 6:
                return new Revision.Base(
                );
            case 7:
                return new Revision.Working(
                );
            case 8:
                return new Revision.Head(
                );
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeRevision.Read()", value));
        }
    }

    public override int AllocationSize(Revision value) {
        switch (value) {
            case Revision.Unspecified variant_value:
                return 4;
            case Revision.Number variant_value:
                return 4
                    + FfiConverterUInt32.INSTANCE.AllocationSize(variant_value.V1);
            case Revision.Date variant_value:
                return 4
                    + FfiConverterInt64.INSTANCE.AllocationSize(variant_value.V1);
            case Revision.Committed variant_value:
                return 4;
            case Revision.Previous variant_value:
                return 4;
            case Revision.Base variant_value:
                return 4;
            case Revision.Working variant_value:
                return 4;
            case Revision.Head variant_value:
                return 4;
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeRevision.AllocationSize()", value));
        }
    }

    public override void Write(Revision value, BigEndianStream stream) {
        switch (value) {
            case Revision.Unspecified variant_value:
                stream.WriteInt(1);
                break;
            case Revision.Number variant_value:
                stream.WriteInt(2);
                FfiConverterUInt32.INSTANCE.Write(variant_value.V1, stream);
                break;
            case Revision.Date variant_value:
                stream.WriteInt(3);
                FfiConverterInt64.INSTANCE.Write(variant_value.V1, stream);
                break;
            case Revision.Committed variant_value:
                stream.WriteInt(4);
                break;
            case Revision.Previous variant_value:
                stream.WriteInt(5);
                break;
            case Revision.Base variant_value:
                stream.WriteInt(6);
                break;
            case Revision.Working variant_value:
                stream.WriteInt(7);
                break;
            case Revision.Head variant_value:
                stream.WriteInt(8);
                break;
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeRevision.Write()", value));
        }
    }
}







